// This function signature demonstrates the need for higher-ranked bounds 
// because it must accept any callable object (F) that has a specific, unknown lifetime ('a).
trait FnForAnyLifetime<T> where T: Debug + 'static {}

fn process_generic_data<T>(factory: impl Fn() -> T) -> T where T: Debug {
    let data = factory();
    println!("Successfully processed data instance.");
    data
}

